function getNewMovesAtLevel(key, level, knownMoveIds) {
  const learnset = LEARNSETS[key] || [];
  return learnset
    .filter(([lv, mk]) => lv === level && !knownMoveIds.includes(mk))
    .map(([lv, mk]) => ({ level: lv, moveKey: mk }));
}

function getLearnsetUpToLevel(key, upToLevel) {
  const learnset = LEARNSETS[key] || [];
  return learnset
    .filter(([lv]) => lv <= upToLevel)
    .map(([lv, mk]) => ({ level: lv, moveKey: mk, move: MOVES_DATA[mk] }))
    .filter(e => e.move);
}